var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"윽……?!","JPN":"うっ……！？","ENG":"Ngh...?!","TWN":"呃……？！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"부학회장을 데려왔소, 학회장.","JPN":"副学会長を連れてきた、学会長。","ENG":"President, I've brought Vice President.","TWN":"我把副學會長帶來了，學會長。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"수고하셨어요, 하이드리히 소장님. 학부장답게 일처리가 깔끔하시네요.","JPN":"ご苦労様です、ハイドリヒ所長。学部長らしい無駄のない仕事ぶりですね。","ENG":"Thank you, Chief Heydrich. As a dean, your work is always spotless.","TWN":"辛苦你了，海德里希所長。不愧是學院院長，辦事就是效率。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"귀빈께서 도착하셨군요. 그렇다면 예정대로 의식을 진행하도록 하죠.","JPN":"貴賓が到着されましたか。それでは予定どおり儀式を行いましょう。","ENG":"The VIP has arrived. Then the ritual shall proceed as planned.","TWN":"貴賓到了呢。那就按照計畫進行儀式吧。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"네. 모쪼록 잘 부탁드려요.","JPN":"はい。どうかよろしくお願いしますね。","ENG":"Yes. Please do.","TWN":"好，那就拜託了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"관악기가 없는 악단의 연주는 기운 잃은 푸념으로 들리기 쉽죠.","JPN":"管楽器のいない楽団の演奏は、勢いのない愚痴に聞こえやすいもの。","ENG":"An orchestra without a trumpet sounds like nails on a chalkboard.","TWN":"沒有管樂器的樂團演奏很容易被聽成有氣無力的呻吟。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"루나, 당신이 자리를 비우는 바람에 연주가 상당히 지연되었어요.","JPN":"ルナ、あなたが留守にしていたせいで演奏がかなり遅れました。","ENG":"Luna, your tardiness has significantly delayed our performance.","TWN":"露娜，因為你不在，演奏推遲了很久。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"지, 지지, 지휘자님…… 저는, 그게 어디까지나…….","JPN":"ま、まま、マエストロ……アタシは、その、あくまで……","ENG":"C-chief Conductor... I was... just...","TWN":"指…指指、…揮家……我，那個……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"부학회장님을 감시한 일이라면 셰나에게 전해 들었습니다.","JPN":"副学会長を監視していたことでしたら、シェナから聞いています。","ENG":"Shena informed me that you were tasked with monitoring the Vice President.","TWN":"監視副學會長的事，我已經聽世娜說了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그러니 이제 본연의 의무로 돌아갈 시간이에요.","JPN":"ですので、もう本来の義務に戻る時間です。","ENG":"However, it is now time you returned to your duties.","TWN":"所以，現在是時候回歸本職工作了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"이번 연주는…… 평소와는 조금 다른 것 같던데…….","JPN":"今回の演奏は……いつもと少し違うようでしたが……","ENG":"The music... It sounds a little different than usual...","TWN":"這次演奏……和平時好像有點不太一樣……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"의외로군요. 당신이 제 지휘에 의문을 가지시는 건가요?","JPN":"意外ですね。あなたが私の指揮に疑問を持つのですか？","ENG":"How odd. Are you questioning my conducting skills, Luna?","TWN":"真意外啊。你是在懷疑我的指揮嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"아, 아뇨! 그건 아니지만요!","JPN":"い、いいえ！　そんなことありません！","ENG":"N-no! Not at all, but...!","TWN":"沒…沒有！不是那樣的！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그래요. 연주 중에는 순종적인 악기가 되도록 노력하세요.","JPN":"そうですか。演奏中は従順な楽器になれるよう、努力しなさい。","ENG":"Good. Now please try to be an obedient instrument while we perform.","TWN":"是的，演奏期間儘量成為順從的樂器吧。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"좋은 음색을 내지 않는 악기는 간수할 가치도 없으니 말입니다.","JPN":"いい音色を出せない楽器はしまっておく価値もありませんので。","ENG":"For an instrument with a bad tone is not worth keeping.","TWN":"因為發不出好音色的樂器，根本不值得收藏。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"……그, 네.","JPN":"……その、はい。","ENG":"...Y-yes, ma'am...","TWN":"……啊，是的。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"반가워요, 레지나 님. 제가 없는 동안 아주 먹음직스러운 친구 분들을 사귀셨네요.","JPN":"またお会いできて嬉しいです、レジーナ様。我々がいない間に、とても美味しそうな友達ができましたね。","ENG":"Hello, Miss Regina. It seems what you made some appetizing friends while we were away.","TWN":"很高興見到你，蕾佳娜。我們不在的這段時間，你交到了看起來很好吃的朋友呢。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};